import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"沙之书","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/4.术法/魔法/法术书/沙之书.md","filePath":"4.资源分区/4.术法/魔法/法术书/沙之书.md"}'),d={name:"4.资源分区/4.术法/魔法/法术书/沙之书.md"};function p(l,a,_,i,b,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"沙之书",tabindex:"-1"},[s("沙之书 "),e("a",{class:"header-anchor",href:"#沙之书","aria-label":'Permalink to "沙之书"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘003A")])])],-1),o('<h1 id="沙之书-1" tabindex="-1">沙之书 <a class="header-anchor" href="#沙之书-1" aria-label="Permalink to &quot;沙之书&quot;">​</a></h1><p>沙之书<br> D+500<br> 本质：魔法本质<br> 这是一本永远翻不到头和尾的书，就如同沙子一样。沙之书无法研读，也无法记住任何沙之书上记载的内容，一旦沙之书合上，将永远再也无法找到之前看到的页面。<br> 在获得沙之书时，你可以从所有以魔力驱动的D级法术中选择一个，即使不翻阅沙之书，你也可以正常使用这道D级法术，当你首次翻阅沙之书时立即遗忘这道法术，并需再支付10XP，此后无需再支付。翻阅沙之书是一个迅捷动作，也可以不翻阅沙之书，而是让它随机展开到某一页。<br> 当你试图利用沙之书进行施法时，你需从上述两项中选择一项，若为前者，则你可以在沙之书上寻找到一道你希望释放的，以魔力驱动的D级法术，这道法术消耗的能量和动作如常；若为后者，则由主持人选择从他最希望看到的结果中选择一道法术或随机一道以魔力驱动的D级法术，并在释放那个法术时需额外支付1点意志，在那次法术释放检定上获得等同于沙之书拥有者智力属性附加*2的表现加值。无论选择哪一项，在找到这道法术的那个回合结束时都会自然遗忘，沙之书将重新合上。<br> 若你寻找到的法术因未掌握派系等原因而无法正常释放，则重新寻找一次，这种找寻方式仅会至多再进行一次。<br> 你可以通过遗忘已经学会的法术，在沙之书上至多记录一个与遗忘的法术相同能量消耗、相同派系（若有）、相同等级且可以被正常释放的，没有前置条件的法术。每个等级的法术至多可以被以此法遗忘并记录一次。在你需要那道法术时，需正常使用此书翻阅一般才能找到那道法术。<br> 当你遗忘法术后，其带来的所有效果都会立即终止。<br> 若你使用了具有限制的法术，则你只能在限制被满足/解除后才能将该法术遗忘并再次使用沙之书。</p><p>在购买沙之书后，解锁下列专长的购买权，如同奥法真理专长一般进行购买。</p><p>迷宫与图书馆（2）<br> 当你获得学识技能等级以获得附加时，你额外获得1点学识技能下属专业。</p><p>花园中的漫步者（4）<br> 你免疫S级及以下的时间回溯效果，当你被敌对单位的时间回溯效果所影响时，若你可以免疫那个效果，则在发动过时间回溯效果的下一轮中额外获得8AP。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',7)])])}const m=r(d,[["render",p]]);export{f as __pageData,m as default};
